import React, { useState } from 'react';
import './App.css';
import { Link} from 'react-router-dom'; 
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom'; 
import Main_Page from './Main_Page'; 
import Diarypage from './diarypage'; 


const Modal = ({ isOpen, onClose }) => { 
    const [isDiarypageOpen, setIsDiarypageOpen] = useState(false);
    const openDiarypage = () => setIsDiarypageOpen(true);
    const closeDiarypage = () => setIsDiarypageOpen(false);

    if (!isOpen) return null;  

    return (
        <Router>
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                    <Link to='/diarypage'>
                    잘자요
                    </Link>
                </li>
                <li>
                    애칭 설정 
                </li>
                <li>
                    Diray List
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
            <Routes>
        <Route path="/" element={<Main_Page openModal={openModal} />} />
        <Route path="/diarypage" element={<Diarypage />} /> 
      </Routes>
        </div>
        </Router>
    );
}

export default Modal;
